import{_ as a,o,i,aB as t}from"./chunks/framework.CoTX8EIa.js";const u=JSON.parse('{"title":"登录相关","description":"","frontmatter":{},"headers":[],"relativePath":"guide/login.md","filePath":"guide/login.md"}'),l={name:"guide/login.md"};function d(p,e,n,r,c,s){return o(),i("div",null,[...e[0]||(e[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/login.md for this page in Markdown format</div><h1 id="登录相关" tabindex="-1">登录相关 <a class="header-anchor" href="#登录相关" aria-label="Permalink to “登录相关”">​</a></h1><p>登录相关功能包括登录、注册、忘记密码等，所有的表单组件均存放在 <code>apps/&lt;app&gt;/src/components/AppAccountForm/</code> 目录下。</p><h2 id="登录" tabindex="-1">登录 <a class="header-anchor" href="#登录" aria-label="Permalink to “登录”">​</a></h2><p>开发者通常在简单熟悉本框架后，涉及到的第一步业务开发就是修改登录功能，将其替换为自己的登录接口。</p><p>但在实践过程中，经常会遇到一些问题，比如：</p><ul><li>替换真实接口后，无法正常登录</li><li>登录接口请求成功，但是无法跳转到后台主页</li><li>...</li></ul><p>针对这些问题你需要依次检查以下几点：</p><ol><li>在 <code>apps/&lt;app&gt;/.env.development</code> 里检查接口请求地址是否正确。</li><li>在 <code>apps/&lt;app&gt;/src/api/index.ts</code> 里修改响应拦截器里的代码，按照实际情况进行调整。例如什么状态下是请求成功，什么状态下是请求异常，并进行错误提示。</li><li>在 <code>apps/&lt;app&gt;/src/api/modules/app.ts</code> 里修改 <code>login</code> 函数，确保接口可以请求成功。</li><li>在 <code>apps/&lt;app&gt;/src/store/modules/account.ts</code> 里修改 <code>isLogin</code> 计算属性，这部分需要根据实际存储的用户信息去判断是否登录。</li></ol><h2 id="注册、忘记密码" tabindex="-1">注册、忘记密码 <a class="header-anchor" href="#注册、忘记密码" aria-label="Permalink to “注册、忘记密码”">​</a></h2><p>如果不需要注册、忘记密码功能，可以在 <code>apps/&lt;app&gt;/src/views/login.vue</code> 中删除相关组件使用的代码。</p>',11)])])}const _=a(l,[["render",d]]);export{u as __pageData,_ as default};
